#include "FlightTransitionComponentData.h"
#include "ArgusLogging.h"
#include "ArgusStaticData.h"

void UFlightTransitionComponentData::InstantiateComponentForEntity(ArgusEntity entity) const
{
	FlightTransitionComponent* FlightTransitionComponentRef = entity.GetOrAddComponent<FlightTransitionComponent>();
	ARGUS_RETURN_ON_NULL(FlightTransitionComponentRef, ArgusECSLog);

	FlightTransitionComponentRef->m_smoothedTransitionAltitude = ArgusMath::SecondOrderSystemSmoother<float>(m_smoothedTransitionAltitudeFrequency, m_smoothedTransitionAltitudeDamping, m_smoothedTransitionAltitudeResponse);
}

void UFlightTransitionComponentData::ReinitializeComponentForEntityPostLoad(ArgusEntity entity) const
{
	FlightTransitionComponent* FlightTransitionComponentRef = entity.GetComponent<FlightTransitionComponent>();
	ARGUS_RETURN_ON_NULL(FlightTransitionComponentRef, ArgusECSLog);

}

void UFlightTransitionComponentData::OnComponentDataLoaded() const
{
}

bool UFlightTransitionComponentData::MatchesType(const UComponentData* other) const
{
	if (!other)
	{
		return false;
	}

	return other->IsA<UFlightTransitionComponentData>();
}
